@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ dcterms:conformsTo <https://w3id.org/cdif/data_description/1.1> ] ;
            sh:resultMessage "A subjectOf catalog record on a CDIF codelist must include dcterms:conformsTo <https://w3id.org/cdif/codelist/1.1>." ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:HasValueConstraintComponent ;
            sh:sourceShape [ a sh:PropertyShape ;
                    sh:hasValue <https://w3id.org/cdif/codelist/1.1> ;
                    sh:message "A subjectOf catalog record on a CDIF codelist must include dcterms:conformsTo <https://w3id.org/cdif/codelist/1.1>." ;
                    sh:minCount 1 ;
                    sh:path dcterms:conformsTo ] ] .

